"menus\")\n}\n\n// ═══════════════════════════════════════════\n// 3. STATISTIK WILAYAH (existing — enhanced)\n// ═══════════════════════════════════════════\nmodel StatistikWilayah {\n  id                Int      @id @default(autoincrement())\n  wilayah           String   @unique @db.VarChar(150)\n  total_porsi       Int      @default(0)\n  jangkauan_sekolah Int      @default(0)\n  target_penerima   Int      @default(0)\n  realisasi_porsi   Int      @default(0)\n  pertumbuhan       String   @default(\"+0%\") @db.VarChar(20)\n  status            String   @default(\"PROSES\") @db.VarChar(50)\n  updatedAt         DateTime @updatedAt\n\n  @@map(\"statistik_wilayah\")\n}\n\n// ═══════════════════════════════════════════\n// 4. BERITA (NEW)\n// ═══════════════════════════════════════════\nmodel Berita {\n  id          Int       @id @default(autoincrement())\n  judul       String    @db.VarChar(300)\n  slug        String    @unique @db.VarChar(350)\n  ringkasan   String    @db.Text\n  konten      String    @db.LongText\n  gambar      String?   @db.VarChar(500)\n  kategori    String    @default(\"Edukasi\") @db.VarChar(100)\n  status      String    @default(\"Draft\") @db.VarChar(50)\n  publishedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  authorId Int\n  author   Admin @relation(fields: [authorId], references: [id])\n\n  @@map(\"berita\")\n}\n\n// ═══════════════════════════════════════════\n// 5. GALERI DOKUMENTASI (NEW)\n// ═══════════════════════════════════════════\nmodel GaleriDokumentasi {\n  id        Int      @id @default(autoincrement())\n  judul     String   @db.VarChar(255)\n  deskripsi String?  @db.Text\n  gambar    String   @db.VarChar(500)\n  lokasi    String?  @db.VarChar(200)\n  tahun     Int?\n  createdAt DateTime @default(now())\n\n  @@map(\"galeri_dokumentasi\")\n}\n\n// ═══════════════════════════════════════════\n// 6. ASPIRASI / PESAN MASUK (NEW)\n// ═══════════════════════════════════════════\nmodel Aspirasi {\n  id        Int      @id @default(autoincrement())\n  nama      String   @db.VarChar(200)\n  email     String?  @db.VarChar(200)\n  kategori  String   @default(\"saran\") @db.VarChar(50)\n  pesan     String   @db.Text\n  status    String   @default(\"BARU\") @db.VarChar(50)\n  createdAt DateTime @default(now())\n\n  @@map(\"aspirasi\")\n}\n\n// ═══════════════════════════════════════════\n// 7. NEWSLETTER SUBSCRIBER (NEW)\n// ═══════════════════════════════════════════\nmodel NewsletterSubscriber {\n  id        Int      @id @default(autoincrement())\n  email     String   @unique @db.VarChar(200)\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  @@map(\"newsletter_subscribers\")\n}\n\n// ═══════════════════════════════════════════\n// 8. ACTIVITY LOG (NEW)\n// ═══════════════════════════════════════════\nmodel ActivityLog {\n  id        Int      @id @default(autoincrement())\n  entity    String   @db.VarChar(100)\n  action    String   @db.VarChar(100)\n  detail    String   @db.Text\n  icon      String?  @default(\"history\") @db.VarChar(50)\n  createdAt DateTime @default(now())\n\n  @@map(\"activity_log\")\n}\n",
